mapper.select:

WHERE 1=1

    AND c.DL_P_RNMCNO = #{custNo}


    AND t.DL_TYP_CCD = #{trxnTpCd}


    AND t.DL_DT >= #{trxnDtFrom}


    AND t.DL_DT <= #{trxnDtTo}

ORDER BY t.DL_DT DESC, t.DL_TM DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM NIC73B t
JOIN NIC66B c ON c.SSPS_DL_CRT_DT = t.SSPS_DL_CRT_DT AND c.SSPS_DL_ID = t.SSPS_DL_ID
WHERE 1=1

    AND c.DL_P_RNMCNO = #{custNo}


    AND t.DL_TYP_CCD = #{trxnTpCd}


    AND t.DL_DT >= #{trxnDtFrom}


    AND t.DL_DT <= #{trxnDtTo}

