mapper.select:

WHERE 1=1

    AND c.DL_P_RNMCNO = #{custNo}


    AND a.GNL_AC_NO = #{acctNo}


    AND t.DL_TYP_CCD = #{trxnTpCd}


    AND t.DL_DT >= #{dtFrom}


    AND t.DL_DT <= #{dtTo}


    AND t.DL_AMT >= #{amtMin}


    AND t.DL_AMT <= #{amtMax}

ORDER BY t.DL_DT DESC, t.DL_TM DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM NIC73B t
JOIN NIC66B c ON c.SSPS_DL_CRT_DT = t.SSPS_DL_CRT_DT AND c.SSPS_DL_ID = t.SSPS_DL_ID
LEFT JOIN NIC75B a ON a.SSPS_DL_CRT_DT = t.SSPS_DL_CRT_DT AND a.SSPS_DL_ID = t.SSPS_DL_ID
WHERE 1=1

    AND c.DL_P_RNMCNO = #{custNo}


    AND a.GNL_AC_NO = #{acctNo}


    AND t.DL_TYP_CCD = #{trxnTpCd}


    AND t.DL_DT >= #{dtFrom}


    AND t.DL_DT <= #{dtTo}


    AND t.DL_AMT >= #{amtMin}


    AND t.DL_AMT <= #{amtMax}
